input.content:
const PROCESSING_FEE = 5;

type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

export const runScenario = (scenario: Scenario): unknown => {
  const results = scenario.steps.map((step) => {
    let basePremium = 0;
    for (const item of step.items) {
      if (item.type === "sword") basePremium += 100;
    }
    const firstInsurance = basePremium * 0.1;
    const premium = Math.ceil(basePremium + firstInsurance) + PROCESSING_FEE;
    return { premium };
  });
  return { results };
};

