const itemBasePremium = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_OF_THREE_BASE_PREMIUM = 60;

const policyBasePremium = (items: Item[]): number => {
  const componentCounts = new Map<string, number>();
  let mainTotal = 0;
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
    } else {
      mainTotal += itemBasePremium(item);
    }
  }
  let componentTotal = 0;
  for (const [type, count] of componentCounts) {
    if (count === 3) {
      componentTotal += BLOCK_OF_THREE_BASE_PREMIUM;
    } else {
      componentTotal += count * itemBasePremium({ type });
    }
  }
  return mainTotal + componentTotal;
};

const quotePremium = (items: Item[]): number => {
  const basePremium = policyBasePremium(items);
  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
  const premiumBeforeFee = Math.ceil(basePremium + firstInsurance);
  return premiumBeforeFee + PROCESSING_FEE;
};

