type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const itemBasePremium = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;

const quotePremium = (items: Item[]): number => {
  const basePremium = items.reduce((sum, item) => sum + itemBasePremium(item), 0);
  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
  const premiumBeforeFee = Math.ceil(basePremium + firstInsurance);
  return premiumBeforeFee + PROCESSING_FEE;
};

export const runScenario = (scenario: Scenario): unknown => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
  return { results };
};

