import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote - base premiums and processing fee
  it("empty item list yields premium of 5 G (only processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("quote for a single plain sword (steel, enchantment 0, not cursed, new customer with no previous contracts) → 100 + 10 (first insurance) + 5 (fee) = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quote for a single plain amulet → 60 + 6 + 5 = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("quote for a single plain staff → 80 + 8 + 5 = 93 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "staff", material: "wood", enchantment: 0, cursed: false }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("quote for a single plain potion → 40 + 4 + 5 = 49 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // Components and blocks
  it("quote for 1 rune → 25 + 3 (first insurance, rounded up) + 5 = 33 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "rune" }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 33 }] });
  });
  it("quote for 2 runes → 50 + 5 + 5 = 60 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "rune" }, { type: "rune" }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("quote for 3 runes (block) → 60 + 6 + 5 = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("quote for 4 runes (no block) → 100 + 10 + 5 = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quote for 7 runes → 175 + 18 (rounded up) + 5 = 198 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: Array.from({ length: 7 }, () => ({ type: "rune" })) },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });
  it("quote for 2 runes + 1 moonstone (no block, different types) → 75 + 8 + 5 = 88 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("quote for 3 runes + 3 moonstones (two separate blocks) → 120 + 12 + 5 = 137 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" }, { type: "rune" }, { type: "rune" },
            { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // Premium modifiers - item-specific
  it("quote for cursed sword adds 50% surcharge on item base premium", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0, cursed: true }] },
      ],
    });
    // 100 base + 50 curse + 10 first insurance (10% of policy base 100) + 5 fee = 165
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it.todo("quote for sword with enchantment 5 adds 30% high-enchantment surcharge");
  it.todo("quote for sword with enchantment 4 has no high-enchantment surcharge");
  it.todo("quote for cursed sword with enchantment 5 applies both surcharges");

  // Premium modifiers - policy-wide
  it.todo("quote for customer with 2 years gets 20% loyalty discount");
  it.todo("quote for customer's second contract gets 15% follow-up discount (no first insurance on customer level — first insurance still applies per-item)");

  // Multi-item policy
  it.todo("quote for cursed sword + plain amulet (newcomer) → 100 + 60 + 50 (curse on sword only) + 16 (first insurance 10%) + 5 = 231 G");

  // Rounding
  it.todo("premium that yields 197.5 G rounds up to 198 G");

  // Integration
  it.todo("newcomer with cursed sword → 165 G");
  it.todo("long-standing customer's second contract with cursed enchanted sword → 160 G");

  // Claim - basic
  it.todo("claim with no special clauses: regular sword (steel, ench 3), damage 500 → payout 400");
  it.todo("claim for rune (no enchantment, no material), damage 200 → payout 100");
  it.todo("claim for sword with enchantment 8 (dragon material), damage 1000 → payout 400 (50% rule, then deductible)");
  it.todo("claim for dragon-material sword, enchantment 5, damage 800 → payout 700");
  it.todo("claim for steel sword, enchantment 9, damage 1000 → payout 400");
  it.todo("claim for dragon-material sword, enchantment 9, damage 1000 → payout 400 (50% wins, then deductible)");

  // Multiple damages per claim
  it.todo("dragon attack damaging sword (500) and amulet (300) → payout 600 (deductible per item)");

  // Cap
  it.todo("policy on a sword (cap 2000), two successive 1500-damage claims: first payout 1400, remainingCap 600; second payout 600, remainingCap 0");

  // Multiple same-type items
  it.todo("policy with two swords; damages for both swords each get their own deductible");
  it.todo("claim with more damages of a type than insured items → CLI rejects (error)");

  // Payout rounding
  it.todo("payout that yields 350.5 G rounds down to 350 G");

  // Edge cases / errors
  it.todo("quote with unknown item type → CLI exits non-zero, error to stderr");
  it.todo("claim referencing damage for item not in policy → CLI exits non-zero");
  it.todo("claim with negative damage amount → CLI exits non-zero");
});

