type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
type Step = { op: "quote"; items: Item[] };
type Customer = { yearsWithMHPCO: number };
type Scenario = { customer: Customer; steps: Step[] };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const basePremiumForType = (type: string): number => BASE_PREMIUM_BY_TYPE[type] ?? 0;
const itemBasePremium = (item: Item): number => basePremiumForType(item.type);

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_OF_THREE_BASE_PREMIUM = 60;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const componentGroupPremium = (type: string, count: number): number =>
  count === BLOCK_SIZE ? BLOCK_OF_THREE_BASE_PREMIUM : count * basePremiumForType(type);

const groupByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const sum = (values: number[]): number => values.reduce((total, value) => total + value, 0);

const policyBasePremium = (items: Item[]): number => {
  const mainItems = items.filter((item) => !isComponent(item));
  const componentItems = items.filter(isComponent);
  const componentCounts = groupByType(componentItems);

  const mainTotal = sum(mainItems.map(itemBasePremium));
  const componentTotal = sum(
    [...componentCounts].map(([type, count]) => componentGroupPremium(type, count)),
  );

  return mainTotal + componentTotal;
};

const CURSE_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;

const itemSurcharges = (item: Item): number => {
  const base = itemBasePremium(item);
  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
  const highEnch =
    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
      : 0;
  return curse + highEnch;
};

const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_YEARS_THRESHOLD = 2;
const FOLLOWUP_DISCOUNT_RATE = 0.15;

const perItemSurcharges = (items: Item[]): number => sum(items.map(itemSurcharges));

const policyWideDiscounts = (
  basePremium: number,
  customer: Customer,
  isFollowUp: boolean,
): number => {
  const loyalty =
    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
  const followUp = isFollowUp ? basePremium * FOLLOWUP_DISCOUNT_RATE : 0;
  return loyalty + followUp;
};

const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
  const basePremium = policyBasePremium(items);
  const surcharges = perItemSurcharges(items);
  const discounts = policyWideDiscounts(basePremium, customer, isFollowUp);
  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
  const premiumBeforeFee = Math.ceil(basePremium + surcharges - discounts + firstInsurance);
  return premiumBeforeFee + PROCESSING_FEE;
};

export const runScenario = (scenario: Scenario): unknown => {
  let quoteCount = 0;
  const results = scenario.steps.map((step) => {
    const isFollowUp = quoteCount > 0;
    quoteCount += 1;
    return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
  });
  return { results };
};

import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote - base premiums and processing fee
  it("empty item list yields premium of 5 G (only processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("quote for a single plain sword (steel, enchantment 0, not cursed, new customer with no previous contracts) → 100 + 10 (first insurance) + 5 (fee) = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quote for a single plain amulet → 60 + 6 + 5 = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("quote for a single plain staff → 80 + 8 + 5 = 93 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "staff", material: "wood", enchantment: 0, cursed: false }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("quote for a single plain potion → 40 + 4 + 5 = 49 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // Components and blocks
  it("quote for 1 rune → 25 + 3 (first insurance, rounded up) + 5 = 33 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "rune" }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 33 }] });
  });
  it("quote for 2 runes → 50 + 5 + 5 = 60 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "rune" }, { type: "rune" }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("quote for 3 runes (block) → 60 + 6 + 5 = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("quote for 4 runes (no block) → 100 + 10 + 5 = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quote for 7 runes → 175 + 18 (rounded up) + 5 = 198 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: Array.from({ length: 7 }, () => ({ type: "rune" })) },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });
  it("quote for 2 runes + 1 moonstone (no block, different types) → 75 + 8 + 5 = 88 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("quote for 3 runes + 3 moonstones (two separate blocks) → 120 + 12 + 5 = 137 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" }, { type: "rune" }, { type: "rune" },
            { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // Premium modifiers - item-specific
  it("quote for cursed sword adds 50% surcharge on item base premium", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0, cursed: true }] },
      ],
    });
    // 100 base + 50 curse + 10 first insurance (10% of policy base 100) + 5 fee = 165
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it("quote for sword with enchantment 5 adds 30% high-enchantment surcharge", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }] },
      ],
    });
    // 100 base + 30 high ench + 10 first ins + 5 fee = 145
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it("quote for sword with enchantment 4 has no high-enchantment surcharge", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 4, cursed: false }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quote for cursed sword with enchantment 5 applies both surcharges", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 5, cursed: true }] },
      ],
    });
    // 100 + 50 curse + 30 high ench + 10 first ins + 5 = 195
    expect(result).toEqual({ results: [{ premium: 195 }] });
  });

  // Premium modifiers - policy-wide
  it("quote for customer with 2 years gets 20% loyalty discount", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] },
      ],
    });
    // 100 base - 20 loyalty + 10 first ins + 5 fee = 95
    expect(result).toEqual({ results: [{ premium: 95 }] });
  });
  it("quote for customer's second contract gets 15% follow-up discount", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] },
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] },
      ],
    }) as { results: { premium: number }[] };
    // First: 115 G (already verified)
    // Second: 100 base - 15 follow-up + 10 first ins + 5 fee = 100
    expect(result.results[1]).toEqual({ premium: 100 });
  });

  // Multi-item policy
  it("quote for cursed sword + plain amulet (newcomer) → 231 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 0, cursed: true },
            { type: "amulet", material: "silver", enchantment: 0, cursed: false },
          ],
        },
      ],
    });
    // 100 + 60 + 50 curse + 16 first ins (10% of 160) + 5 = 231
    expect(result).toEqual({ results: [{ premium: 231 }] });
  });

  // Rounding
  it("premium that yields 197.5 G rounds up to 198 G", () => {
    // 7 runes: base 175 + 17.5 first insurance + 5 fee = 197.5 → 198
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: Array.from({ length: 7 }, () => ({ type: "rune" })) },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });

  // Integration
  it("newcomer with cursed sword (steel, ench 3) → 165 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it("long-standing customer's second contract with cursed enchanted sword → 160 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 3 },
      steps: [
        { op: "quote", items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }] },
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 7, cursed: true }] },
      ],
    }) as { results: { premium: number }[] };
    expect(result.results[1]).toEqual({ premium: 160 });
  });

  // Claim - basic
  it.todo("claim with no special clauses: regular sword (steel, ench 3), damage 500 → payout 400");
  it.todo("claim for rune (no enchantment, no material), damage 200 → payout 100");
  it.todo("claim for sword with enchantment 8 (dragon material), damage 1000 → payout 400 (50% rule, then deductible)");
  it.todo("claim for dragon-material sword, enchantment 5, damage 800 → payout 700");
  it.todo("claim for steel sword, enchantment 9, damage 1000 → payout 400");
  it.todo("claim for dragon-material sword, enchantment 9, damage 1000 → payout 400 (50% wins, then deductible)");

  // Multiple damages per claim
  it.todo("dragon attack damaging sword (500) and amulet (300) → payout 600 (deductible per item)");

  // Cap
  it.todo("policy on a sword (cap 2000), two successive 1500-damage claims: first payout 1400, remainingCap 600; second payout 600, remainingCap 0");

  // Multiple same-type items
  it.todo("policy with two swords; damages for both swords each get their own deductible");
  it.todo("claim with more damages of a type than insured items → CLI rejects (error)");

  // Payout rounding
  it.todo("payout that yields 350.5 G rounds down to 350 G");

  // Edge cases / errors
  it.todo("quote with unknown item type → CLI exits non-zero, error to stderr");
  it.todo("claim referencing damage for item not in policy → CLI exits non-zero");
  it.todo("claim with negative damage amount → CLI exits non-zero");
});

